import{T as e,d as t,l as n}from"./chunks/runtime-core.esm-bundler.tX4qagM3.js";import{t as r}from"./chunks/plugin-vue_export-helper.JQk_Kig_.js";var i=JSON.parse(`{"title":"从输入 URL 开始到浏览器解析过程","description":"","frontmatter":{},"headers":[],"relativePath":"browser/url/parsing-process.md","filePath":"browser/url/parsing-process.md"}`),a={name:`browser/url/parsing-process.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="从输入-url-开始到浏览器解析过程" tabindex="-1">从输入 URL 开始到浏览器解析过程 <a class="header-anchor" href="#从输入-url-开始到浏览器解析过程" aria-label="Permalink to “从输入 URL 开始到浏览器解析过程”">​</a></h1><hr><p><strong>整体分成 7 大阶段：</strong></p><ul><li>URL 解析 &amp; 缓存判断</li><li>DNS 域名解析</li><li>TCP 三次握手 + HTTPS TLS 协商</li><li>HTTP 请求发送 &amp; 响应接收</li><li>浏览器解析 HTML / CSS / JS 构建渲染树</li><li>布局 Layout → 绘制 Paint → 合成 Composite</li><li>JS 执行、事件绑定、页面交互就绪</li></ul><h2 id="浏览器输入-url-先做本地预处理" tabindex="-1">浏览器输入 URL，先做本地预处理 <a class="header-anchor" href="#浏览器输入-url-先做本地预处理" aria-label="Permalink to “浏览器输入 URL，先做本地预处理”">​</a></h2><h3 id="url-语法解析" tabindex="-1">URL 语法解析 <a class="header-anchor" href="#url-语法解析" aria-label="Permalink to “URL 语法解析”">​</a></h3><p>浏览器先拆解 URL 各部分：</p><p>协议 <code>http/https</code>、域名、端口、路径、参数、哈希 <code>#</code></p><h3 id="浏览器缓存优先级判断" tabindex="-1">浏览器缓存优先级判断 <a class="header-anchor" href="#浏览器缓存优先级判断" aria-label="Permalink to “浏览器缓存优先级判断”">​</a></h3><p>顺序：</p><p>Memory Cache → Disk Cache → 强制缓存 → 协商缓存</p><ul><li>先看内存缓存：当前 tab 内存里有没有，有直接拿</li><li>再看硬盘缓存：本地有没有过期缓存</li><li>没缓存才走网络请求</li></ul><blockquote><p>前端关联： 静态资源缓存策略、Cache-Control、ETag、Last-Modified 都是在这一步生效。</p></blockquote><h3 id="hsts-预解析" tabindex="-1">HSTS / 预解析 <a class="header-anchor" href="#hsts-预解析" aria-label="Permalink to “HSTS / 预解析”">​</a></h3><p>浏览器自带 HSTS 列表，强制跳转 HTTPS；</p><p>同时触发 DNS 预解析 <code>&lt;link rel=&quot;dns-prefetch&quot;&gt;</code>。</p><h2 id="dns-域名解析-域名-→-ip" tabindex="-1">DNS 域名解析（域名 → IP） <a class="header-anchor" href="#dns-域名解析-域名-→-ip" aria-label="Permalink to “DNS 域名解析（域名 → IP）”">​</a></h2><p>浏览器不知道域名在哪，必须翻译成服务器 IP。</p><p><strong>递归查询流程</strong></p><p>浏览器缓存 → 系统缓存 → 路由器缓存 → 运营商 DNS → 根域名服务器 → 顶级域名服务器 → 目标域名服务器</p><p><strong>前端关联点</strong></p><ul><li>页面多域名请求多，DNS 耗时高</li><li>优化：<code>&lt;link rel=&quot;dns-prefetch&quot; href=&quot;https://xxx.com&quot;&gt;</code> 预解析</li><li>域名收敛：减少页面跨域名数量，减少 DNS 开销</li></ul><h2 id="tcp-三次握手-https-tls-握手" tabindex="-1">TCP 三次握手 + HTTPS TLS 握手 <a class="header-anchor" href="#tcp-三次握手-https-tls-握手" aria-label="Permalink to “TCP 三次握手 + HTTPS TLS 握手”">​</a></h2><h3 id="tcp-三次握手" tabindex="-1">TCP 三次握手 <a class="header-anchor" href="#tcp-三次握手" aria-label="Permalink to “TCP 三次握手”">​</a></h3><p>建立可靠连接，保证数据不丢、不乱序。</p><h3 id="https-tls-协商-4-次握手" tabindex="-1">HTTPS TLS 协商（4 次握手） <a class="header-anchor" href="#https-tls-协商-4-次握手" aria-label="Permalink to “HTTPS TLS 协商（4 次握手）”">​</a></h3><ul><li>证书校验（域名匹配、是否过期、是否可信）</li><li>协商加密算法、生成会话密钥</li><li>之后所有数据加密传输</li></ul><blockquote><p>有些网站首次打开慢，就是 TLS 证书校验、握手耗时； 优化：<strong>HTTPS 会话复用、HTTP/2、HTTP/3</strong>。</p></blockquote><h2 id="发起-http-请求-接收响应" tabindex="-1">发起 HTTP 请求 &amp; 接收响应 <a class="header-anchor" href="#发起-http-请求-接收响应" aria-label="Permalink to “发起 HTTP 请求 &amp; 接收响应”">​</a></h2><h3 id="构建请求报文" tabindex="-1">构建请求报文 <a class="header-anchor" href="#构建请求报文" aria-label="Permalink to “构建请求报文”">​</a></h3><p>请求行、请求头、请求体。</p><ul><li>请求头 <code>User-Agent</code>、<code>Cookie</code>、<code>Referer</code>、<code>Origin</code></li><li>跨域就是浏览器在这一步做同源策略拦截</li></ul><h3 id="服务器处理-返回响应" tabindex="-1">服务器处理 &amp; 返回响应 <a class="header-anchor" href="#服务器处理-返回响应" aria-label="Permalink to “服务器处理 &amp; 返回响应”">​</a></h3><p>响应行、响应头、响应体（HTML 源码）</p><h3 id="前端关键知识点" tabindex="-1">前端关键知识点 <a class="header-anchor" href="#前端关键知识点" aria-label="Permalink to “前端关键知识点”">​</a></h3><ul><li>跨域 CORS、预检 OPTIONS 请求</li><li>状态码 200/301/302/304/404/502</li><li>响应头控制缓存、跨域、内容类型</li></ul><h2 id="浏览器解析-html-构建-dom-树" tabindex="-1">浏览器解析 HTML，构建 DOM 树 <a class="header-anchor" href="#浏览器解析-html-构建-dom-树" aria-label="Permalink to “浏览器解析 HTML，构建 DOM 树”">​</a></h2><p><strong>字节流 → 词法解析 → 语法解析 → DOM 树</strong></p><p>浏览器一边下载 HTML、一边流式解析，不用等全部下载完。</p><p><strong>关键规则</strong></p><ul><li>遇到 <code>&lt;link&gt;</code> 外链 CSS：并行下载，不阻塞 HTML 解析，但阻塞渲染</li><li>遇到 <code>&lt;script&gt;</code> 外链 JS：阻塞 HTML 解析、阻塞渲染 <ul><li>没有 <code>defer/async</code> 时，页面会卡在这</li></ul></li><li><code>defer</code>：后台下载，顺序执行，等 HTML 解析完再跑</li><li><code>async</code>：后台下载，下载完立刻乱序执行</li></ul><blockquote><p>JS 放底部、defer/async、动态 import 按需加载，都是为了不阻塞 HTML 解析。</p></blockquote><h2 id="解析-css-生成-cssom-树-渲染树" tabindex="-1">解析 CSS，生成 CSSOM 树 + 渲染树 <a class="header-anchor" href="#解析-css-生成-cssom-树-渲染树" aria-label="Permalink to “解析 CSS，生成 CSSOM 树 + 渲染树”">​</a></h2><ul><li>浏览器解析 CSS → 生成 CSSOM 样式规则树</li><li>DOM + CSSOM 合并 → 渲染树 Render Tree <ul><li>只包含需要显示的节点</li><li><code>display: none</code> 不会进入渲染树</li><li><code>visibility: hidden</code> 会进渲染树，占空间</li></ul></li></ul><h2 id="页面渲染三大流程" tabindex="-1">页面渲染三大流程 <a class="header-anchor" href="#页面渲染三大流程" aria-label="Permalink to “页面渲染三大流程”">​</a></h2><h3 id="layout-布局-重排" tabindex="-1">Layout 布局（重排） <a class="header-anchor" href="#layout-布局-重排" aria-label="Permalink to “Layout 布局（重排）”">​</a></h3><p>根据渲染树，计算每个元素精确宽高、位置、几何坐标。</p><p><strong>触发重排场景：</strong></p><ul><li>改变宽高、边距、定位、字体大小</li><li>获取 offsetTop /offsetLeft/clientWidth 等布局属性</li></ul><blockquote><p>循环频繁读写布局属性，导致强制同步布局、大量重排卡顿。</p></blockquote><h3 id="paint-绘制-重绘" tabindex="-1">Paint 绘制（重绘） <a class="header-anchor" href="#paint-绘制-重绘" aria-label="Permalink to “Paint 绘制（重绘）”">​</a></h3><p>按照布局结果，填充像素：</p><p>颜色、背景、阴影、文字、图片。</p><p>只改颜色、背景 → 只重绘，不重排，性能更好。</p><h3 id="composite-图层合成" tabindex="-1">Composite 图层合成 <a class="header-anchor" href="#composite-图层合成" aria-label="Permalink to “Composite 图层合成”">​</a></h3><p>浏览器把页面分成多个合成图层，交给 GPU 合成。</p><p><strong>开启独立图层条件</strong></p><ul><li><code>transform: translateZ(0)</code></li><li><code>will-change</code></li><li>3D transform、video、canvas</li></ul><blockquote><p>能用 transform/opacity 做动画，绝不改 top/left 因为 transform 只走 合成层，不触发重排、重绘，GPU 加速丝滑。</p></blockquote><h2 id="js-执行、domcontentloaded、load-事件" tabindex="-1">JS 执行、DOMContentLoaded、Load 事件 <a class="header-anchor" href="#js-执行、domcontentloaded、load-事件" aria-label="Permalink to “JS 执行、DOMContentLoaded、Load 事件”">​</a></h2><h3 id="js-执行" tabindex="-1">JS 执行 <a class="header-anchor" href="#js-执行" aria-label="Permalink to “JS 执行”">​</a></h3><p>JS 可以操作 DOM/CSS，会重新触发渲染树、重排重绘。</p><h3 id="domcontentloaded" tabindex="-1">DOMContentLoaded <a class="header-anchor" href="#domcontentloaded" aria-label="Permalink to “DOMContentLoaded”">​</a></h3><p>HTML 解析完、DOM 构建完成，不用等图片、样式、视频</p><p>→ 前端适合在这里初始化业务逻辑、挂载 Vue/React 根实例</p><h3 id="window-onload" tabindex="-1">window.onload <a class="header-anchor" href="#window-onload" aria-label="Permalink to “window.onload”">​</a></h3><p>所有资源（图片、字体、视频、样式）全部加载完才触发</p><p>→ 适合做页面统计、加载完成弹窗</p><h2 id="整条链路对应-前端工程师-的工作" tabindex="-1">整条链路对应 前端工程师 的工作 <a class="header-anchor" href="#整条链路对应-前端工程师-的工作" aria-label="Permalink to “整条链路对应 前端工程师 的工作”">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>前端日常工作 &amp; 优化点</th></tr></thead><tbody><tr><td>缓存</td><td>配置 Cache-Control、静态资源缓存、哈希命名</td></tr><tr><td>DNS</td><td>dns-prefetch、减少多域名</td></tr><tr><td>网络</td><td>启用 HTTP2、CDN、压缩 gzip</td></tr><tr><td>请求</td><td>跨域处理、接口超时、请求头配置</td></tr><tr><td>HTML 解析</td><td>JS 放底部、defer/async、避免阻塞</td></tr><tr><td>渲染树</td><td>合理使用 display:none 减少渲染节点</td></tr><tr><td>重排重绘</td><td>避免频繁操作 DOM、批量修改样式</td></tr><tr><td>动画</td><td>用 transform/opacity 做动画，GPU 加速</td></tr><tr><td>事件</td><td>利用 DOMContentLoaded 合理时机初始化代码</td></tr></tbody></table><h2 id="简述" tabindex="-1">简述 <a class="header-anchor" href="#简述" aria-label="Permalink to “简述”">​</a></h2><p>URL 解析查缓存 → DNS 域名解析 → TCP 握手 + HTTPS 加密 → HTTP 请求响应 → 解析 HTML 建 DOM → 解析 CSS 建 CSSOM 合成渲染树 → 布局重排 → 绘制重绘 → 图层合成 → JS 执行页面就绪。</p>`,72)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};